-- REL - Relative: signed offset for branches
-- returns target address as PC + offset (signed)
CREATE OR REPLACE FUNCTION pg6502.addr_relative(p_pc INT)
RETURNS INT AS $$
DECLARE
    v_offset INT;
BEGIN
    v_offset := pg6502.mem_read(p_pc + 1);
    IF v_offset >= 128 THEN
        v_offset := v_offset - 256;
    END IF;
    RETURN p_pc + 2 + v_offset;
END
$$ LANGUAGE plpgsql

-- JMP: Jump to address
CREATE OR REPLACE FUNCTION pg6502.op_jmp(p_mode TEXT, p_pc INT)
RETURNS VOID AS $$
DECLARE v_addr INT;
BEGIN
    CASE p_mode
        WHEN 'absolute'  THEN v_addr := pg6502.addr_absolute(p_pc);
        WHEN 'indirect'  THEN v_addr := pg6502.addr_indirect(p_pc);
    END CASE;
    UPDATE pg6502.cpu SET pc = v_addr;
END;
$$ LANGUAGE plpgsql

-- (IND,X) - Indexed Indirect: (ZP + X) then deref
-- e.g. LDA ($20,X) with X=5 -> read ptr from $0025
CREATE OR REPLACE FUNCTION pg6502.addr_indirect_x(p_pc INT)
RETURNS INT AS $$
DECLARE
    v_x  INT;
    v_ptr INT;
BEGIN
    SELECT x INTO v_x from pg6502.cpu;
    v_ptr := (pg6502.mem_read(p_pc + 1) + v_x) & 255;
    RETURN pg6502.mem_read16(v_ptr);
END
$$ LANGUAGE plpgsql

-- (IND),Y - Indirect Indexed: deref then add Y
-- e.g. LDA ($20),Y -> read ptr from $0020, add Y
CREATE OR REPLACE FUNCTION pg6502.addr_indirect_y(p_pc INT)
RETURNS INT AS $$
DECLARE
    v_y  INT;
    v_ptr INT;
BEGIN
    SELECT y INTO v_y from pg6502.cpu;
    v_ptr := pg6502.mem_read16(pg6502.mem_read(p_pc + 1));
    RETURN v_ptr + v_y;
END
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION switch_role() RETURNS void
  LANGUAGE plpgsql
  AS $$
declare
  user_id text;
Begin
  user_id = (current_setting('request.jwt.claims')::json->>'id')::text;
  if user_id = '1'::text then
    execute 'set local role postgrest_test_author';
  elseif user_id = '2'::text then
    execute 'set local role postgrest_test_default_role';
  elseif user_id = '3'::text then
    RAISE EXCEPTION 'Disabled ID --> %', user_id USING HINT = 'Please contact administrator';
  end if;
end
$$;

-- ZP,Y - zero page, y: just like ZP but with an Y reg added.
CREATE OR REPLACE FUNCTION pg6502.addr_zero_page_y(p_pc INT)
RETURNS INT AS $$
DECLARE
    v_y INT;
BEGIN
    SELECT y INTO v_y from pg6502.cpu;
    RETURN (pg6502.mem_read(p_pc + 1) + v_y) & 255;
END
$$ LANGUAGE plpgsql

CREATE FUNCTION alter_table_under_transition_tables_upd_func()
  RETURNS TRIGGER
  LANGUAGE plpgsql
AS $$
BEGIN
  RAISE WARNING 'old table = %, new table = %',
                  (SELECT string_agg(id || '=' || name, ',') FROM d),
                  (SELECT string_agg(id || '=' || name, ',') FROM i);
  RAISE NOTICE 'one = %', (SELECT 1 FROM alter_table_under_transition_tables LIMIT 1);
  RETURN NULL;
END;
$$

