-- ABS,X: absolute x: 16 bit addr with X added.
CREATE OR REPLACE FUNCTION pg6502.addr_absolute_x(p_pc INT)
RETURNS INT AS $$
DECLARE
    v_x  INT;
BEGIN
    SELECT x INTO v_x from pg6502.cpu;
    RETURN (pg6502.mem_read16(p_pc + 1) + v_x);
END
$$ LANGUAGE plpgsql

-- ABS,Y: absolute y: 16 bit addr with Y added.
CREATE OR REPLACE FUNCTION pg6502.addr_absolute_y(p_pc INT)
RETURNS INT AS $$
DECLARE
    v_y  INT;
BEGIN
    SELECT y INTO v_y from pg6502.cpu;
    RETURN (pg6502.mem_read16(p_pc + 1) + v_y);
END
$$ LANGUAGE plpgsql

-- Stack operations (stack lives at $0100-$01FF, grows down from $FF)
CREATE OR REPLACE FUNCTION pg6502.stack_push(p_val INT)
RETURNS VOID AS $$
DECLARE
    v_sp INT;
BEGIN
    SELECT sp INTO v_sp FROM pg6502.cpu;
    PERFORM pg6502.mem_write(256 + v_sp, p_val);
    UPDATE pg6502.cpu SET sp = (v_sp - 1) & 255;
END
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION pg6502.op_dex() RETURNS VOID AS $$
DECLARE v_val INT;
BEGIN
    SELECT (x + 255) & 255 INTO v_val FROM pg6502.cpu;
    UPDATE pg6502.cpu SET x = v_val, pc = pc + 1;
    PERFORM pg6502.set_nz(v_val);
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION pg6502.op_dey() RETURNS VOID AS $$
DECLARE v_val INT;
BEGIN
    SELECT (y + 255) & 255 INTO v_val FROM pg6502.cpu;
    UPDATE pg6502.cpu SET y = v_val, pc = pc + 1;
    PERFORM pg6502.set_nz(v_val);
END;
$$ LANGUAGE plpgsql

-- JSR: Jump to Subroutine - push return address (PC-1) onto stack
CREATE OR REPLACE FUNCTION pg6502.op_jsr(p_pc INT)
RETURNS VOID AS $$
DECLARE v_pc INT; v_lo INT; v_hi INT;
BEGIN
    v_pc := p_pc + 2; -- PC points past the instruction
    v_lo := v_pc & 255;
    v_hi := (v_pc >> 8) & 255;
    PERFORM pg6502.stack_push(v_hi);
    PERFORM pg6502.stack_push(v_lo);
    UPDATE pg6502.cpu SET pc = pg6502.addr_absolute(p_pc);
END;
$$ LANGUAGE plpgsql
